import { useRef, useEffect, useState } from "react";
import * as THREE from "three";

/* GLB embedded as base64 — no network needed */
const GLB_B64 = "";

/* ---- minimal GLB parser (single mesh + baseColor texture) ---- */
const CTYPE = { 5120: Int8Array, 5121: Uint8Array, 5122: Int16Array, 5123: Uint16Array, 5125: Uint32Array, 5126: Float32Array };
const TSIZE = { SCALAR: 1, VEC2: 2, VEC3: 3, VEC4: 4 };

function decodeB64(b64) {
  const bin = atob(b64);
  const buf = new ArrayBuffer(bin.length);
  const u8 = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
  return buf;
}

function parseGLB(buf) {
  const dv = new DataView(buf);
  const jsonLen = dv.getUint32(12, true);
  const json = JSON.parse(new TextDecoder().decode(new Uint8Array(buf, 20, jsonLen)));
  let off = 20 + jsonLen;
  const binLen = dv.getUint32(off, true);
  const bin = buf.slice(off + 8, off + 8 + binLen);
  return { json, bin };
}

function readAccessor(json, bin, idx) {
  const a = json.accessors[idx];
  const bv = json.bufferViews[a.bufferView];
  const Arr = CTYPE[a.componentType];
  const n = TSIZE[a.type];
  const bpe = Arr.BYTES_PER_ELEMENT;
  /* interleaved (byteStride) — quantized GLBs pack all attributes together */
  if (bv.byteStride && bv.byteStride !== n * bpe) {
    const arr = new Arr(bin, bv.byteOffset || 0, bv.byteLength / bpe);
    const ib = new THREE.InterleavedBuffer(arr, bv.byteStride / bpe);
    return new THREE.InterleavedBufferAttribute(ib, n, (a.byteOffset || 0) / bpe, !!a.normalized);
  }
  const byteOffset = (bv.byteOffset || 0) + (a.byteOffset || 0);
  return new THREE.BufferAttribute(new Arr(bin, byteOffset, a.count * n), n, !!a.normalized);
}

function buildModel() {
  const { json, bin } = parseGLB(decodeB64(GLB_B64));
  const prim = json.meshes[0].primitives[0];
  const geo = new THREE.BufferGeometry();
  geo.setAttribute("position", readAccessor(json, bin, prim.attributes.POSITION));
  if (prim.attributes.NORMAL !== undefined)
    geo.setAttribute("normal", readAccessor(json, bin, prim.attributes.NORMAL));
  if (prim.attributes.TEXCOORD_0 !== undefined)
    geo.setAttribute("uv", readAccessor(json, bin, prim.attributes.TEXCOORD_0));
  if (prim.indices !== undefined) geo.setIndex(readAccessor(json, bin, prim.indices));

  const mat = new THREE.MeshStandardMaterial({ color: 0xffffff, metalness: 0.08, roughness: 0.85 });

  /* texture from embedded jpeg — data URL (sandbox-safe) */
  if (json.images && json.images.length) {
    const bv = json.bufferViews[json.images[0].bufferView];
    const jpg = new Uint8Array(bin, bv.byteOffset || 0, bv.byteLength);
    let s = "";
    for (let i = 0; i < jpg.length; i += 8192)
      s += String.fromCharCode.apply(null, jpg.subarray(i, i + 8192));
    const dataUrl = "data:" + json.images[0].mimeType + ";base64," + btoa(s);
    new THREE.TextureLoader().load(
      dataUrl,
      (tex) => {
        tex.flipY = false;
        tex.encoding = THREE.sRGBEncoding;
        mat.map = tex;
        mat.needsUpdate = true;
      },
      undefined,
      () => { /* texture blocked → keep untextured stone look */ mat.color.set(0xcfc9bd); }
    );
  }

  const mesh = new THREE.Mesh(geo, mat);
  const node = json.nodes.find((n) => n.mesh === 0) || {};
  if (node.scale) mesh.scale.set(...node.scale);
  if (node.translation) mesh.position.set(...node.translation);
  return mesh;
}

/* ---------- scene ---------- */
function StatueScene() {
  const mountRef = useRef(null);
  const [ready, setReady] = useState(false);
  const [err, setErr] = useState(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(mount.clientWidth, mount.clientHeight);
    renderer.outputEncoding = THREE.sRGBEncoding;
    mount.appendChild(renderer.domElement);

    const scene = new THREE.Scene();
    scene.fog = new THREE.Fog(0x0a0a0a, 9, 16);
    const camera = new THREE.PerspectiveCamera(40, mount.clientWidth / mount.clientHeight, 0.1, 50);
    camera.position.set(0, 0.6, 6.2);
    camera.lookAt(0, 0.2, 0);

    /* gallery lighting */
    scene.add(new THREE.AmbientLight(0x303040, 1.1));
    const key = new THREE.SpotLight(0xfff2dd, 2.0, 30, Math.PI / 5, 0.45);
    key.position.set(0, 8, 4);
    scene.add(key);
    const rim = new THREE.PointLight(0xd4af37, 1.8, 18);
    rim.position.set(4, 2, -3.5);
    scene.add(rim);
    const fill = new THREE.PointLight(0x6878b8, 0.55, 22);
    fill.position.set(-4, 0.5, 3);
    scene.add(fill);

    /* pedestal */
    const pedestal = new THREE.Group();
    const disc = new THREE.Mesh(
      new THREE.CylinderGeometry(2.0, 2.15, 0.18, 64),
      new THREE.MeshStandardMaterial({ color: 0x101010, metalness: 0.4, roughness: 0.35 })
    );
    const ring = new THREE.Mesh(
      new THREE.TorusGeometry(2.02, 0.012, 12, 96),
      new THREE.MeshBasicMaterial({ color: 0xd4af37 })
    );
    ring.rotation.x = Math.PI / 2;
    ring.position.y = 0.09;
    pedestal.add(disc, ring);
    pedestal.position.y = -1.75;
    scene.add(pedestal);

    /* statue */
    const pivot = new THREE.Group();
    scene.add(pivot);
    let statue, buildError = null;
    try {
      statue = buildModel();
    } catch (e) {
      buildError = String(e && e.message || e);
      setErr(buildError);
      statue = new THREE.Group();
    }
    /* normalize: known bbox height ~1.0 → scale up, sit on pedestal */
    const wrapper = new THREE.Group();
    wrapper.add(statue);
    wrapper.scale.setScalar(3.1);
    wrapper.position.y = -0.1;
    pivot.add(wrapper);

    /* dust particles for atmosphere */
    const dustGeo = new THREE.BufferGeometry();
    const dustPos = new Float32Array(300 * 3);
    for (let i = 0; i < 300; i++) {
      dustPos[i * 3] = (Math.random() - 0.5) * 10;
      dustPos[i * 3 + 1] = Math.random() * 6 - 2;
      dustPos[i * 3 + 2] = (Math.random() - 0.5) * 8;
    }
    dustGeo.setAttribute("position", new THREE.BufferAttribute(dustPos, 3));
    const dust = new THREE.Points(
      dustGeo,
      new THREE.PointsMaterial({ color: 0xd4af37, size: 0.018, transparent: true, opacity: 0.45 })
    );
    scene.add(dust);

    /* interaction */
    const target = { x: 0, y: 0 };
    let lastMove = 0;
    const onPointer = (e) => {
      const pt = e.touches ? e.touches[0] : e;
      target.x = (pt.clientX / window.innerWidth) * 2 - 1;
      target.y = -((pt.clientY / window.innerHeight) * 2 - 1);
      lastMove = performance.now();
    };
    window.addEventListener("pointermove", onPointer, { passive: true });
    window.addEventListener("touchmove", onPointer, { passive: true });

    const onResize = () => {
      camera.aspect = mount.clientWidth / mount.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mount.clientWidth, mount.clientHeight);
    };
    window.addEventListener("resize", onResize);

    const reduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    const clock = new THREE.Clock();
    let raf, idleAngle = 0;

    const animate = () => {
      raf = requestAnimationFrame(animate);
      const dt = Math.min(clock.getDelta(), 0.05);
      const t = clock.elapsedTime;

      /* idle: slow turntable resumes 2s after last cursor move */
      const idleNow = performance.now() - lastMove > 2000;
      if (idleNow && !reduced) idleAngle += dt * 0.25;

      const ry = idleAngle + target.x * 0.85;
      const rx = -target.y * 0.18;
      pivot.rotation.y += (ry - pivot.rotation.y) * 0.06;
      pivot.rotation.x += (rx - pivot.rotation.x) * 0.06;

      if (!reduced) {
        pivot.position.y = Math.sin(t * 0.7) * 0.05;
        rim.intensity = 1.8 + Math.sin(t * 1.5) * 0.3;
        dust.rotation.y = t * 0.02;
      }

      /* camera subtle parallax */
      camera.position.x += (target.x * 0.35 - camera.position.x) * 0.03;
      camera.position.y += (0.6 + target.y * 0.2 - camera.position.y) * 0.03;
      camera.lookAt(0, 0.2, 0);

      renderer.render(scene, camera);
    };
    animate();
    requestAnimationFrame(() => setReady(true));

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("pointermove", onPointer);
      window.removeEventListener("touchmove", onPointer);
      window.removeEventListener("resize", onResize);
      scene.traverse((o) => {
        if (o.geometry) o.geometry.dispose();
        if (o.material) { if (o.material.map) o.material.map.dispose(); o.material.dispose(); }
      });
      renderer.dispose();
      mount.removeChild(renderer.domElement);
    };
  }, []);

  return (
    <div style={{ position: "absolute", inset: 0 }}>
      <div
        ref={mountRef}
        style={{ width: "100%", height: "100%", opacity: ready ? 1 : 0, transition: "opacity 1.6s ease" }}
      />
      {err && (
        <div style={{ position: "absolute", top: 16, left: 16, zIndex: 20, color: "#ff7a7a", fontSize: 12, fontFamily: "monospace", maxWidth: "80%" }}>
          PARSE ERROR: {err}
        </div>
      )}
      {!ready && (
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 14 }}>
          <span style={{ width: 30, height: 30, border: "2px solid rgba(212,175,55,0.25)", borderTopColor: "#D4AF37", borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />
          <span style={{ color: "#8a7a4a", fontSize: 11, letterSpacing: "0.25em" }}>LOADING SCULPTURE</span>
        </div>
      )}
    </div>
  );
}

/* ---------- gallery page ---------- */
export default function DigitalSculpture() {
  return (
    <div
      style={{
        position: "relative", width: "100%", height: "100vh",
        background: "radial-gradient(ellipse at 50% 30%, #15151c 0%, #0a0a0a 65%)",
        overflow: "hidden",
        fontFamily: "'Helvetica Neue', -apple-system, 'PingFang TC', 'Noto Sans TC', sans-serif",
      }}
    >
      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes riseIn { from { opacity:0; transform:translateY(14px); } to { opacity:1; transform:translateY(0); } }
        @media (prefers-reduced-motion: reduce) { * { animation-duration: 0.01s !important; } }
      `}</style>

      <StatueScene />

      {/* gallery label */}
      <div style={{ position: "absolute", left: 32, bottom: 34, zIndex: 10, animation: "riseIn 1s ease 0.8s both" }}>
        <p style={{ margin: 0, fontSize: 10, letterSpacing: "0.34em", color: "#D4AF37" }}>NOX COLLECTION · No. 001</p>
        <h2 style={{ margin: "10px 0 6px", fontSize: 26, fontWeight: 600, color: "#f0ead8", letterSpacing: "0.02em" }}>
          墮落與飛升
        </h2>
        <p style={{ margin: 0, fontSize: 12, color: "#8a8a8a", lineHeight: 1.7 }}>
          AI 生成雕塑 · Tripo3D / 2026<br />
          移動游標環視作品 — 靜止後雕像將自行緩慢旋轉
        </p>
      </div>
    </div>
  );
}
